SELECT

FROM recovery_payment t0 left join project_info t2 on t0.project_id = t2.id and t2.is_deleted = 0


    AND t0.create_stamp BETWEEN

      #{item}



    AND t0.pay_date BETWEEN

      #{item}



    AND (t2.affiliated_org IN
          #{item}
      OR

      t2.manage LIKE CONCAT('%',#{item},'%')

    )


    AND t0.flow_state = #{request.flowState}


    AND t0.id = #{request.id}


    AND t0.project_id in

      #{item}



    AND t0.lawyer_id = #{request.lawyerId}


    AND t0.project_id = #{request.projectId}


    AND t0.lawyer_name LIKE CONCAT ('%',#{request.lawyerName},'%')


    AND t0.tenant_id = #{request.tenantId}


    AND t0.creator = #{request.creator}


    AND t0.create_stamp = #{request.createStamp}


    AND t0.last_editor = #{request.lastEditor}


    AND t0.last_edit_stamp = #{request.lastEditStamp}


    AND t0.pay_amount = #{request.payAmount}


    AND t0.pay_date = #{request.payDate}


    AND t0.payee LIKE CONCAT ('%',#{request.payee},'%')


    AND t0.receiving_account LIKE CONCAT ('%',#{request.receivingAccount},'%')


    AND t0.receiving_bank LIKE CONCAT ('%',#{request.receivingBank},'%')


    AND t0.pay_status = #{request.payStatus}


    AND t0.project_name LIKE CONCAT ('%',#{request.projectName},'%')


    AND t0.pay_explain = #{request.payExplain}


    AND t0.remarks = #{request.remarks}


    AND t0.is_deleted = #{request.isDeleted}




    ORDER BY ${request.field} ${request.order}


    ORDER BY t0.id DESC

